import React, {Component} from 'react'

class Comment extends Component {
    render() {
        const {user, text} = this.props.comment
        console.log('render Comment')
        return (
            <div>
                <h6>{user}</h6>
                <p>{text}</p>
            </div>
        )
    }
}

export default Comment
